//! Embedded HTML pages for the web UI

/// Chinese HTML (default)
pub const INDEX_HTML_ZH: &str = r#"<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Sublink Worker - 订阅转换工具</title>
    <style>
        :root{--bg-primary:#f5f5f5;--bg-secondary:#fff;--text-primary:#1a1a1a;--text-secondary:#666;--border-color:#e0e0e0;--primary-color:#3b82f6;--radius-md:.5rem;--radius-lg:.75rem}[data-theme=dark]{--bg-primary:#0f0f0f;--bg-secondary:#1a1a1a;--text-primary:#fff;--text-secondary:#a0a0a0;--border-color:#333;--primary-color:#60a5fa}*{margin:0;padding:0;box-sizing:border-box}body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;background:var(--bg-primary);color:var(--text-primary);min-height:100vh}.navbar{background:var(--bg-secondary);border-bottom:1px solid var(--border-color);padding:1rem;position:fixed;top:0;left:0;right:0;z-index:100}.navbar-content{max-width:1200px;margin:0 auto;display:flex;justify-content:space-between;align-items:center}.brand{display:flex;align-items:center;gap:.5rem;font-size:1.25rem;font-weight:700}.nav-links{display:flex;gap:1rem;align-items:center}.nav-links a{color:var(--text-secondary);text-decoration:none}.main{padding-top:80px;padding-bottom:2rem}.container{max-width:800px;margin:0 auto;padding:0 1rem}.hero{text-align:center;padding:2rem 0}.hero h1{font-size:2.5rem;font-weight:800;margin-bottom:.5rem}.hero p{color:var(--text-secondary);font-size:1.125rem}.card{background:var(--bg-secondary);border-radius:var(--radius-lg);padding:1.5rem;margin:1.5rem 0;box-shadow:0 4px 6px rgba(0,0,0,.1)}.form-group{margin-bottom:1.5rem}.form-label{display:block;font-weight:600;margin-bottom:.5rem}.form-textarea{width:100%;padding:.75rem;border:1px solid var(--border-color);border-radius:var(--radius-md);background:var(--bg-primary);color:var(--text-primary);font-family:inherit;min-height:120px;resize:vertical}.form-textarea:focus{outline:none;border-color:var(--primary-color)}.options{display:flex;flex-wrap:wrap;gap:.5rem}.option{display:flex;align-items:center;gap:.5rem;padding:.5rem 1rem;background:var(--bg-primary);border:1px solid var(--border-color);border-radius:var(--radius-md);cursor:pointer}.option:hover{border-color:var(--primary-color)}.btn{display:inline-flex;align-items:center;gap:.5rem;padding:.75rem 1.5rem;border:none;border-radius:var(--radius-md);font-weight:600;cursor:pointer}.btn-primary{background:var(--primary-color);color:#fff}.btn-secondary{background:#6b7280;color:#fff}.btn:disabled{opacity:.7;cursor:not-allowed}.output{background:var(--bg-primary);border-radius:var(--radius-md);padding:1rem;max-height:400px;overflow:auto}.output pre{white-space:pre-wrap;word-break:break-word;font-family:monospace;font-size:.875rem}.hidden{display:none}.footer{background:var(--bg-secondary);border-top:1px solid var(--border-color);padding:1.5rem;text-align:center;margin-top:auto}.toast{position:fixed;bottom:2rem;left:50%;transform:translateX(-50%);background:var(--bg-secondary);padding:.75rem 1.5rem;border-radius:var(--radius-md);box-shadow:0 10px 15px rgba(0,0,0,.1);z-index:1000}.theme-toggle{background:none;border:none;font-size:1.25rem;cursor:pointer;padding:.5rem}select{padding:.375rem;border:1px solid var(--border-color);border-radius:var(--radius-md);background:var(--bg-primary);color:var(--text-primary)}
    </style>
</head>
<body>
    <nav class="navbar"><div class="navbar-content"><div class="brand">🔗 Sublink Worker</div><div class="nav-links"><select id="langSelect" onchange="location.href='?lang='+this.value"><option value="zh-CN" selected>中文</option><option value="en">English</option><option value="fa">فارسی</option><option value="ru">Русский</option></select><button class="theme-toggle" onclick="toggleTheme()">🌙</button><a href="https://github.com/7Sageer/sublink-worker" target="_blank">GitHub</a></div></div></nav>
    <main class="main"><div class="container"><div class="hero"><h1>Sublink Worker</h1><p>轻量级订阅转换和管理工具</p></div><div class="card"><form id="form" onsubmit="return generateConfig(event)"><div class="form-group"><label class="form-label">输入订阅链接或配置</label><textarea class="form-textarea" id="input" placeholder="请输入订阅链接或 Base64 配置..." required></textarea></div><div class="form-group"><label class="form-label">输出格式</label><div class="options"><label class="option"><input type="radio" name="format" value="singbox" checked> 📦 Sing-Box</label><label class="option"><input type="radio" name="format" value="clash"> ⚔️ Clash</label><label class="option"><input type="radio" name="format" value="surge"> 🌊 Surge</label><label class="option"><input type="radio" name="format" value="xray"> ✈️ Xray</label></div></div><div class="form-group"><label class="form-label">规则集</label><div class="options"><label class="option"><input type="checkbox" name="rule" value="Ad Block"> Ad Block</label><label class="option"><input type="checkbox" name="rule" value="AI Services"> AI Services</label><label class="option"><input type="checkbox" name="rule" value="Bilibili"> Bilibili</label><label class="option"><input type="checkbox" name="rule" value="Youtube"> Youtube</label><label class="option"><input type="checkbox" name="rule" value="Google" checked> Google</label><label class="option"><input type="checkbox" name="rule" value="Private"> Private</label><label class="option"><input type="checkbox" name="rule" value="Location:CN"> Location:CN</label><label class="option"><input type="checkbox" name="rule" value="Telegram"> Telegram</label><label class="option"><input type="checkbox" name="rule" value="Github"> Github</label><label class="option"><input type="checkbox" name="rule" value="Microsoft"> Microsoft</label><label class="option"><input type="checkbox" name="rule" value="Apple"> Apple</label><label class="option"><input type="checkbox" name="rule" value="Social Media"> Social Media</label><label class="option"><input type="checkbox" name="rule" value="Streaming"> Streaming</label><label class="option"><input type="checkbox" name="rule" value="Gaming"> Gaming</label><label class="option"><input type="checkbox" name="rule" value="Education"> Education</label><label class="option"><input type="checkbox" name="rule" value="Financial"> Financial</label><label class="option"><input type="checkbox" name="rule" value="Cloud Services"> Cloud Services</label><label class="option"><input type="checkbox" name="rule" value="Non-China" checked> Non-China</label></div></div><div class="form-group"><button type="submit" class="btn btn-primary" id="genBtn">⚡ 生成配置</button><button type="button" class="btn btn-secondary" onclick="createShortLink()">🔗 创建短链接</button></div></form></div><div class="card hidden" id="outputCard"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:1rem"><h3>输出结果</h3><div style="display:flex;gap:.5rem"><button class="btn" onclick="copyOutput()">📋</button><button class="btn" onclick="downloadConfig()">⬇️</button></div></div><div class="output"><pre id="outputContent"></pre></div><div style="margin-top:1rem"><label class="form-label">订阅链接：</label><div style="display:flex;gap:.5rem"><input type="text" id="outputUrl" class="form-textarea" readonly style="flex:1;min-height:auto"><button class="btn btn-secondary" onclick="copyUrl()">复制</button></div></div></div><div class="card hidden" id="shortlinkCard"><h3 style="margin-bottom:1rem">短链接</h3><div style="display:flex;gap:.5rem"><input type="text" id="shortlinkUrl" class="form-textarea" readonly style="flex:1;min-height:auto"><button class="btn btn-secondary" onclick="copyShortlink()">复制</button></div></div></div></main>
    <footer class="footer"><p>© 2024 Sublink Worker. MIT License.</p></footer>
    <div class="toast hidden" id="toast"></div>
    <script>function initTheme(){const theme=localStorage.getItem('theme')||(window.matchMedia('(prefers-color-scheme: dark)').matches?'dark':'light');document.documentElement.setAttribute('data-theme',theme);updateThemeIcon(theme)}function toggleTheme(){const current=document.documentElement.getAttribute('data-theme');const next=current==='dark'?'light':'dark';document.documentElement.setAttribute('data-theme',next);localStorage.setItem('theme',next);updateThemeIcon(next)}function updateThemeIcon(theme){document.querySelector('.theme-toggle').textContent=theme==='dark'?'☀️':'🌙'}function showToast(msg){const toast=document.getElementById('toast');toast.textContent=msg;toast.classList.remove('hidden');setTimeout(()=>toast.classList.add('hidden'),3000)}async function copy(text){try{await navigator.clipboard.writeText(text);showToast('已复制')}catch{showToast('复制失败')}}function copyOutput(){copy(document.getElementById('outputContent').textContent)}function copyUrl(){copy(document.getElementById('outputUrl').value)}function copyShortlink(){copy(document.getElementById('shortlinkUrl').value)}function downloadConfig(){const content=document.getElementById('outputContent').textContent;const format=document.querySelector('input[name="format"]:checked').value;const ext={singbox:'json',clash:'yaml',surge:'conf',xray:'txt'}[format]||'txt';const blob=new Blob([content],{type:'text/plain'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='sublink.'+ext;a.click();URL.revokeObjectURL(a.href)}async function generateConfig(e){e.preventDefault();const input=document.getElementById('input').value.trim();if(!input){showToast('请输入订阅链接');return}const format=document.querySelector('input[name="format"]:checked').value;const rules=Array.from(document.querySelectorAll('input[name="rule"]:checked')).map(cb=>cb.value);const url='/'+format+'?config='+encodeURIComponent(input)+'&selectedRules='+encodeURIComponent(JSON.stringify(rules));document.getElementById('genBtn').disabled=true;document.getElementById('genBtn').textContent='生成中...';try{const res=await fetch(url);const text=await res.text();document.getElementById('outputContent').textContent=text;document.getElementById('outputUrl').value=url;document.getElementById('outputCard').classList.remove('hidden');document.getElementById('shortlinkCard').classList.add('hidden');showToast('生成成功')}catch(err){showToast('错误：'+err.message)}document.getElementById('genBtn').disabled=false;document.getElementById('genBtn').textContent='⚡ 生成配置'}async function createShortLink(){const input=document.getElementById('input').value.trim();if(!input){showToast('请输入订阅链接');return}const format=document.querySelector('input[name="format"]:checked').value;const rules=Array.from(document.querySelectorAll('input[name="rule"]:checked')).map(cb=>cb.value);const url='/'+format+'?config='+encodeURIComponent(input)+'&selectedRules='+encodeURIComponent(JSON.stringify(rules));try{const res=await fetch('/shorten-v2?url='+encodeURIComponent(url));const code=await res.text();document.getElementById('shortlinkUrl').value=location.origin+'/b/'+code;document.getElementById('shortlinkCard').classList.remove('hidden');showToast('短链接创建成功')}catch(err){showToast('错误：'+err.message)}}initTheme();const urlLang=new URLSearchParams(location.search).get('lang');if(urlLang)document.getElementById('langSelect').value=urlLang</script>
</body>
</html>"#;

